let spotFuturesLoading = false;
let spotFuturesHasData = false;
let spotSort = {key:'open_spread', direction:'desc'};
let spotFuturesSearch = '';
let spotFundingInterval = 'all';
let spotBasisOpenings = {};
let dualBasisOpenings = {};
let dualIndexRows = new Map();
let basisOpeningDetails = new Map();
let spotFuturesSearchTimer;
let suggestionRequest = 0;
let marketRefreshCountdownTimer;
let dualMarketRefreshCountdownTimer;
let dualFuturesPage = 1;
let dualFuturesLoading = false;
let dualFuturesHasData = false;
let dualFuturesSearch = '';
let dualFuturesSearchTimer;
let dualSort = {key:'open_spread',direction:'desc'};
let alertSignature = '';
let alertsInitialized = false;
let alertCountdownTimer;
