let latestAlertGroups = [];
let alarmSoundEnabled = localStorage.getItem('arbi-alarm-sound') === 'on';
let alarmAudioContext;

async function loadDashboard(){const data=await (await fetch('/api/dashboard')).json();byId('bestSpread').textContent=data.summary.best_spread.toFixed(3)+'%';byId('markets').textContent=data.summary.markets_scanned;byId('activeStrategies').textContent=data.summary.active_strategies;byId('mode').textContent=data.summary.mode;byId('updated').textContent='最近更新 '+new Date().toLocaleTimeString('zh-CN');byId('opportunities').innerHTML=data.opportunities.map(x=>`<tr><td class="symbol">${x.symbol}</td><td>${money(x.buy_price)}<span class="exchange">${x.buy_exchange}</span></td><td>${money(x.sell_price)}<span class="exchange">${x.sell_exchange}</span></td><td class="profit">${x.spread.toFixed(3)}%</td><td class="profit">+${x.estimated_profit.toFixed(3)}%</td><td class="funding ${x.funding>=0?'profit':''}">${x.funding>=0?'+':''}${x.funding.toFixed(4)}%</td><td>${x.updated_at}</td></tr>`).join('')}
function dailyTrendItem(item){return `<article><b>${item.symbol}</b><span class="${changeClass(item.change_24h)}">24H ${displayChange(item.change_24h)}</span><small>7D ${displayChange(item.change_7d)}</small></article>`}
function hornSignalItem(item,index){return `<article><b>${index+1}</b><button class="symbol-detail-trigger" onclick="openSymbolDetail('${item.symbol}')">${item.symbol}</button><span class="horn-timeframe">${item.timeframe.toUpperCase()}</span><span>结构分 <em class="horn-score">${Number(item.score).toFixed(1)}</em></span><span>价格 <em class="positive">${percent(item.price_change)}</em></span><span>OI <em class="positive">${percent(item.oi_change)}</em></span><span>人数比 <em class="negative">${percent(item.ratio_change)}</em></span><span class="${item.cvd_confirmed?'horn-cvd-confirmed':'horn-cvd-divergent'}">CVD ${item.cvd_confirmed?'确认上涨':'背离/未确认'}</span></article>`}
async function loadDailyTrends(){const data=await (await fetch('/api/daily-report/trends')).json();byId('dailyHorn30m').innerHTML=data.horn_30m?.length?data.horn_30m.map(hornSignalItem).join(''):'<p class="empty-alert">今日暂无 30 分钟犄型候选。</p>';byId('dailyHorn4h').innerHTML=data.horn_4h?.length?data.horn_4h.map(hornSignalItem).join(''):'<p class="empty-alert">今日暂无 4H 犄型候选。</p>'}
async function loadDailyListings(){const data=await (await fetch('/api/daily-report/listings')).json();byId('dailyListings').innerHTML=data.events.length?data.events.map(item=>`<article><b>${item.symbol}</b><span class="listing-${item.type==='上架'?'up':'down'}">${item.type}</span><small>${item.exchange} · ${item.occurred_at}</small></article>`).join(''):'<p class="empty-alert">已建立当前 Binance 永续合约基线；最近 30 天暂无上下架变化。</p>'}
async function loadStrategies(){const data=await (await fetch('/api/strategies')).json();byId('strategyList').innerHTML=data.map(x=>`<article class="strategy"><div><h3>${x.name}<span class="tag ${x.enabled?'':'off'}">${x.enabled?'运行中':'已暂停'}</span></h3><p>${x.mode} · ${x.symbol}</p></div><button onclick="toggleStrategy(${x.id})">${x.enabled?'暂停':'启用'}</button></article>`).join('')}
async function toggleStrategy(id){await fetch('/api/strategies/'+id,{method:'PATCH'});loadStrategies();loadDashboard()}
function openModal(){byId('modal').classList.remove('hidden')}function closeModal(){byId('modal').classList.add('hidden')}
async function saveStrategy(e){e.preventDefault();const res=await fetch('/api/strategies',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({name:byId('name').value,mode:byId('strategyMode').value,symbol:byId('symbol').value})});if(!res.ok){alert((await res.json()).error);return}e.target.reset();closeModal();loadStrategies();loadDashboard()}
function percent(value){return `${value>=0?'+':''}${Number(value).toFixed(4)}%`}
function signClass(value){return Number(value)>=0?'positive':'negative'}
function intervalClass(hours){return [1,2,4,8].includes(Number(hours))?`interval-${hours}`:'interval-other'}
function displayFunding(value){return value===null||value===undefined?'—':percent(value)}
function fundingStack(row){return `<div class="funding-stack"><span class="funding-item"><b>当前</b><span class="${signClass(row.funding_rate)}">${displayFunding(row.funding_rate)}</span></span><span class="funding-item"><b>上期</b><span class="${signClass(row.funding_previous)}">${displayFunding(row.funding_previous)}</span></span><span class="funding-item"><b>24H</b><span class="${signClass(row.funding_24h)}">${displayFunding(row.funding_24h)}</span></span><span class="funding-item"><b>3D</b><span class="${signClass(row.funding_3d)}">${displayFunding(row.funding_3d)}</span></span><span class="funding-item"><b>7D</b><span class="${signClass(row.funding_7d)}">${displayFunding(row.funding_7d)}</span></span><span class="funding-item"><b>30D</b><span class="${signClass(row.funding_30d)}">${displayFunding(row.funding_30d)}</span></span></div>`}
const trendPeriods=[['change_5m','5MIN'],['change_15m','15MIN'],['change_30m','30MIN'],['change_1h','1H'],['change_12h','12H'],['change_24h','24H'],['change_3d','3D'],['change_7d','7D']];
const spotSortLabels={basis:'基差',funding_rate:'当前资费',funding_previous:'上期资费',funding_24h:'24H 资费',funding_3d:'3D 资费',funding_7d:'7D 资费',funding_30d:'30D 资费',change_5m:'5MIN 涨跌幅',change_15m:'15MIN 涨跌幅',change_30m:'30MIN 涨跌幅',change_1h:'1H 涨跌幅',change_12h:'12H 涨跌幅',change_24h:'24H 涨跌幅',change_3d:'3D 涨跌幅',change_7d:'7D 涨跌幅',open_spread:'开差',close_spread:'平差'};
function changeClass(value){return value===null||value===undefined?'neutral':Number(value)>0?'positive':Number(value)<0?'negative':'neutral'}
function displayChange(value){return value===null||value===undefined?'—':percent(value)}
function trendLights(row){return `<div class="trend-lights">${trendPeriods.map(([key,label])=>`<span class="trend-light ${changeClass(row[key])}" title="${label} ${displayChange(row[key])}"><i></i><em>${label}</em></span>`).join('')}</div>`}
function priceChangeStack(row){return `<div class="change-stack">${trendPeriods.map(([key,label])=>`<span class="change-item"><b>${label}</b><span class="${changeClass(row[key])}">${displayChange(row[key])}</span></span>`).join('')}</div>`}
const exchangeIcon={Binance:'/static/exchanges/binance.png',Gate:'/static/exchanges/gate.png',Bitget:'/static/exchanges/bitget.png',Bybit:'/static/exchanges/bybit.png',OKX:'/static/exchanges/okx.png'};
function exchangeName(exchange){const icon=exchangeIcon[exchange];return `${icon?`<img class="exchange-logo" src="${icon}" alt="${exchange}">`:''}${exchange}`}
function coinglassKlineUrl(symbol){return `https://www.coinglass.com/tv/zh/Binance_${encodeURIComponent(symbol.replace('/',''))}`}
function liquidityLevel(value){const amount=Number(value||0);return amount>=10000000?'safe':amount>=5000000?'warn-light':amount>=1000000?'warn-medium':'warn-deep'}
function liquidityAmount(value){const amount=Number(value);if(!Number.isFinite(amount)||amount<=0)return '—';return amount>=1e9?`$${(amount/1e9).toFixed(2)}B`:`$${(amount/1e6).toFixed(2)}M`}
function liquidityMetric(label,value){return `<span class="liquidity-metric ${liquidityLevel(value)}"><b>${label}</b><i>${liquidityAmount(value)}</i></span>`}
function spotLiquidity(row){return `<div class="liquidity-stack">${liquidityMetric('交易量',row.spot_volume)}</div>`}
function futuresLiquidity(row){return `<div class="liquidity-stack">${liquidityMetric('持仓量',row.futures_open_interest)}${liquidityMetric('交易量',row.futures_volume)}</div>`}
function spotTransferStatus(row){const chains=Array.isArray(row.transfer_networks)?row.transfer_networks:[];if(!chains.length)return `<span class="transfer-status pending">充提待确认</span>`;const deposits=chains.filter(chain=>chain.deposit_open).length,withdrawals=chains.filter(chain=>chain.withdraw_open).length,closed=chains.filter(chain=>!chain.deposit_open||!chain.withdraw_open),payload=encodeURIComponent(JSON.stringify(chains));return `<span class="transfer-status ${closed.length?'transfer-alert':''}" data-transfer-chains="${payload}" onmouseenter="showTransferTip(this)" onmouseleave="destroyFloatingPopup()">充${deposits}/${chains.length} · 提${withdrawals}/${chains.length}${closed.length?` · ${closed.length}链关闭`:''}</span>`}
function showTransferTip(trigger){destroyFloatingPopup();let chains=[];try{chains=JSON.parse(decodeURIComponent(trigger.dataset.transferChains||''))}catch(error){return}const open=(key)=>chains.filter(chain=>chain[key]).map(chain=>chain.name).join('/')||'关闭',closed=chains.filter(chain=>!chain.deposit_open||!chain.withdraw_open).map(chain=>chain.name).join('/');const popup=document.createElement('div');popup.dataset.floatingDetail='transfer';popup.className='floating-detail-popup transfer-popup';popup.innerHTML=`<div>充值：<b>${open('deposit_open')}</b></div><div>提现：<b>${open('withdraw_open')}</b>${closed?` <em>${closed}（关闭）</em>`:''}</div>`;document.body.appendChild(popup);positionFloatingPopup(popup,trigger)}
function spotRows(symbols){
  return symbols.map(group=>{
    const contract=group.rows[0],span=group.rows.length;
    const shared=`<td class="contract-cell" rowspan="${span}">${exchangeName('Binance')} 合约</td><td rowspan="${span}">${futuresLiquidity(contract)}</td><td class="${signClass(contract.basis)} numeric" rowspan="${span}">${percent(contract.basis)}</td><td rowspan="${span}">${fundingStack(contract)}</td><td rowspan="${span}"><span class="interval-badge ${intervalClass(contract.funding_interval_hours)}">${contract.funding_interval_hours}H</span><span class="exchange">下次 ${contract.next_funding_time}</span></td>`;
    return group.rows.map((row,index)=>{
      return `<tr>${index===0?`<td class="symbol" rowspan="${span}">${trendLights(contract)}<div><button class="symbol-detail-trigger ${group.delisting_announced?'delisting-symbol':''}" onclick="openSymbolDetail('${group.symbol}')">${group.symbol}</button><a class="kline-link" href="${coinglassKlineUrl(group.symbol)}" target="_blank" rel="noopener noreferrer">K线</a></div></td><td class="price-change-cell" rowspan="${span}">${priceChangeStack(contract)}</td>`:''}<td>${spotLiquidity(row)}</td><td class="spot-cell">${exchangeName(row.long_exchange)}${spotTransferStatus(row)}</td>${index===0?shared:''}<td class="${signClass(row.open_spread)} numeric">${percent(row.open_spread)}</td><td class="${signClass(row.close_spread)} numeric">${percent(row.close_spread)}</td></tr>`;
    }).join('');
  }).join('');
}
function showMarketRefreshCountdown(seconds){clearInterval(marketRefreshCountdownTimer);let remaining=Math.max(0,Number(seconds)||0);const target=byId('spotFuturesCountdown');const render=()=>{target.textContent=remaining>0?` · 下次行情同步约 ${remaining} 秒`:' · 正在等待下一轮行情同步…'};render();marketRefreshCountdownTimer=setInterval(()=>{remaining=Math.max(0,remaining-1);render();if(remaining===0)clearInterval(marketRefreshCountdownTimer)},1000)}
async function loadSpotFutures(manual=false){
  if(spotFuturesLoading)return;
  spotFuturesLoading=true;
  const status=byId('spotFuturesUpdated'),bnOnly=byId('binanceSpotOnly').checked;
  if(manual)status.textContent='正在读取已缓存的行情数据…';
  try{
    const response=await fetch('/api/spot-futures?page='+spotFuturesPage+'&binance_spot_only='+(bnOnly?'1':'0')+'&funding_interval='+encodeURIComponent(spotFundingInterval)+'&symbol='+encodeURIComponent(spotFuturesSearch)+'&sort_by='+spotSort.key+'&sort_direction='+spotSort.direction);
    const data=await response.json();
    if(!response.ok)throw new Error(data.error||'行情服务暂不可用');
    destroyFloatingPopup();spotBasisOpenings=Object.fromEntries(data.symbols.map(group=>[group.symbol,group.basis_opening]));byId('spotFuturesRows').innerHTML=data.symbols.length?spotRows(data.symbols):'<tr><td colspan="12" class="loading">没有符合条件的交易对。</td></tr>';
    spotFuturesHasData=true;
    updateSortHeaders();
    byId('pageInfo').textContent=`第 ${data.page} / ${data.pages} 页 · 共 ${data.total_symbols} 个币种`;
    const pageSelect=byId('spotFuturesPageSelect');
    pageSelect.innerHTML=Array.from({length:data.pages},(_,index)=>`<option value="${index+1}" ${index+1===data.page?'selected':''}>${index+1}</option>`).join('');
    byId('previousPage').disabled=data.page<=1;
    byId('nextPage').disabled=data.page>=data.pages;
    const failed=Object.keys(data.errors||{});
    const detail=failed.length?failed.join('、')+' 行情暂不可用':`已对全部 ${data.total_symbols} 个币种排序后分页 · 当前按${spotSortLabels[spotSort.key]}排序`;
    status.textContent=`最近更新 ${data.updated_at} · ${detail}`;
    showMarketRefreshCountdown(data.next_refresh_in_seconds);
  }catch(error){
    if(!spotFuturesHasData)byId('spotFuturesRows').innerHTML=`<tr><td colspan="11" class="loading">${error.message}</td></tr>`;
    status.textContent=spotFuturesHasData?'本次更新失败，已保留上一组有效数据。':error.message;
  }finally{spotFuturesLoading=false}
}
function groupSortValue(group){const rows=group.rows;if(spotSort.key==='open_spread'||spotSort.key==='close_spread')return Math.max(...rows.map(row=>Number(row[spotSort.key])));return Number(rows[0][spotSort.key])}
function sortGroups(groups){return [...groups].sort((a,b)=>{const delta=groupSortValue(a)-groupSortValue(b);return spotSort.direction==='desc'?-delta:delta})}
function updateSortHeaders(){document.querySelectorAll('.sort-header').forEach(button=>{const active=button.dataset.sort===spotSort.key;button.classList.toggle('active',active);button.textContent=button.textContent.replace(/ [↑↓]$/,'')+(active?(spotSort.direction==='desc'?' ↓':' ↑'):'')})}
function setSpotSort(key){spotSort=spotSort.key===key?{key,direction:spotSort.direction==='desc'?'asc':'desc'}:{key,direction:'desc'};spotFuturesPage=1;updateSortHeaders();loadSpotFutures(true)}
function changeSpotFuturesPage(change){spotFuturesPage=Math.max(1,spotFuturesPage+change);loadSpotFutures(true)}
function selectSpotFuturesPage(page){spotFuturesPage=Math.max(1,Number(page)||1);loadSpotFutures(true)}
function setBinanceSpotFilter(){spotFuturesPage=1;loadSpotFutures(true)}
function setSpotFundingInterval(interval){spotFundingInterval=interval;spotFuturesPage=1;document.querySelectorAll('.spot-period-filter').forEach(button=>button.classList.toggle('active',button.dataset.spotPeriod===interval));loadSpotFutures(true)}
async function loadSymbolSuggestions(scope,query){const panel=byId(scope+'Suggestions');const normalized=query.trim();if(!normalized){panel.innerHTML='';panel.classList.add('hidden');return}const requestId=++suggestionRequest;try{const response=await fetch('/api/symbol-suggestions?q='+encodeURIComponent(normalized));const data=await response.json();if(requestId!==suggestionRequest)return;panel.innerHTML=data.items.length?data.items.map(item=>`<button type="button" class="symbol-suggestion" onclick="selectSymbolSuggestion('${scope}','${item.symbol}','${item.label}')"><span>${item.name||item.symbol.split('/')[0]}</span><small>${item.symbol}${item.live?'':' · 暂无当前行情'}</small></button>`).join(''):'<p class="no-suggestion">没有匹配的币种</p>';panel.classList.remove('hidden')}catch(error){panel.innerHTML='';panel.classList.add('hidden')}}
function selectSymbolSuggestion(scope,symbol,label){const input=byId(scope+'Search');input.value=label;byId(scope+'Suggestions').classList.add('hidden');if(scope==='spotFutures'){spotFuturesSearch=symbol;spotFuturesPage=1;loadSpotFutures(true);return}dualFuturesSearch=symbol;dualFuturesPage=1;loadDualFutures(true)}
function setSpotFuturesSearch(value){spotFuturesSearch=value.trim();spotFuturesPage=1;loadSymbolSuggestions('spotFutures',value);clearTimeout(spotFuturesSearchTimer);spotFuturesSearchTimer=setTimeout(()=>loadSpotFutures(true),180)}
function setDualFuturesSearch(value){const query=value.trim();dualFuturesSearch=query;dualFuturesPage=1;loadSymbolSuggestions('dualFutures',query);clearTimeout(dualFuturesSearchTimer);dualFuturesSearchTimer=setTimeout(()=>loadDualFutures(true),180)}
function dualDisplayPercent(value){return value===null||value===undefined?'—':percent(value)}
function dualTrendLights(group){return `<div class="trend-lights">${trendPeriods.map(([key,label])=>`<span class="trend-light ${changeClass(group['binance_'+key])}" title="${label} ${displayChange(group['binance_'+key])}"><i></i><em>${label}</em></span>`).join('')}</div>`}
function dualPriceChanges(group){return `<div class="change-stack">${trendPeriods.map(([key,label])=>`<span class="change-item"><b>${label}</b><span class="${changeClass(group['binance_'+key])}">${displayChange(group['binance_'+key])}</span></span>`).join('')}</div>`}
function dualInterval(value){return value===null||value===undefined?'—':`${value}H`}
function dualContractLeg(exchange,basis){return `<span><b>${exchangeName(exchange)}</b><i class="${changeClass(basis)}">基差 ${dualDisplayPercent(basis)}</i></span>`}
function dualFundingRates(row){return `<div class="dual-funding"><span><b>多</b><i>${dualDisplayPercent(row.long_funding_rate)}</i><em class="interval-badge ${intervalClass(row.long_funding_interval_hours)}">${dualInterval(row.long_funding_interval_hours)}</em></span><span><b>空</b><i>${dualDisplayPercent(row.short_funding_rate)}</i><em class="interval-badge ${intervalClass(row.short_funding_interval_hours)}">${dualInterval(row.short_funding_interval_hours)}</em></span></div>`}
function dualFundingDifference(row){return `<div class="${changeClass(row.funding_difference)} dual-funding-diff"><b>${dualDisplayPercent(row.funding_difference)}</b><small>${row.funding_settlement_label||'结算时间待同步'}</small></div>`}
function dualLiquidity(row){return `<div class="liquidity-stack dual-liquidity"><span><b>多</b>${liquidityMetric('持仓量',row.long_open_interest)}${liquidityMetric('交易量',row.long_volume)}</span><span><b>空</b>${liquidityMetric('持仓量',row.short_open_interest)}${liquidityMetric('交易量',row.short_volume)}</span></div>`}
function componentMaps(row){return {long:Object.fromEntries((row.long_index_components||[]).map(item=>[item.source,item])),short:Object.fromEntries((row.short_index_components||[]).map(item=>[item.source,item]))}}
function localIndexOverlap(row){const {long,short}=componentMaps(row);return Object.keys(long).reduce((total,source)=>total+(short[source]?Math.min(Number(long[source].weight)||0,Number(short[source].weight)||0):0),0)*100}
function componentCompareRows(row){const {long,short}=componentMaps(row);return [...new Set([...Object.keys(long),...Object.keys(short)])].sort().map(source=>{const left=long[source],right=short[source],name=left?.name||right?.name,first=Number(left?.weight||0)*100,second=Number(right?.weight||0)*100;return `<article class="component-compare"><div><b>${name}</b><span>${row.long_exchange} ${first.toFixed(2)}% · ${row.short_exchange} ${second.toFixed(2)}%</span></div><div class="component-compare-bar"><i class="long" style="width:${first.toFixed(2)}%"></i><i class="short" style="width:${second.toFixed(2)}%"></i></div></article>`}).join('')}
function dualIndexOverlap(row){const longComponents=row.long_index_components||[],shortComponents=row.short_index_components||[];if(row.index_overlap===null||row.index_overlap===undefined)return `<span class="common-index-empty">${row.index_status||'成分待同步'}</span>`;if(!longComponents.length||!shortComponents.length)return '<span class="common-index-empty">指数成分不可用</span>';const overlap=Math.max(0,Math.min(100,localIndexOverlap(row)));return `<div class="common-index" data-common-index-id="${row._commonIndexId}"><b class="common-index-trigger" onmouseenter="showCommonIndexTip(this)" onmouseleave="destroyFloatingPopup()">${overlap.toFixed(2)}%</b></div>`}
function dualRows(symbols){return symbols.map(group=>{const span=group.rows.length;return group.rows.map((row,index)=>`<tr class="${index===0?'dual-group-start ':index===span-1?'dual-group-end':'dual-group-body'}">${index===0?`<td class="symbol" rowspan="${span}">${dualTrendLights(group)}<div><button class="symbol-detail-trigger ${group.delisting_announced?'delisting-symbol':''}" onclick="openSymbolDetail('${group.symbol}')">${group.symbol}</button><a class="kline-link" href="${coinglassKlineUrl(group.symbol)}" target="_blank" rel="noopener noreferrer">K线</a></div></td><td class="price-change-cell" rowspan="${span}">${dualPriceChanges(group)}</td>`:''}<td>${dualLiquidity(row)}</td><td class="dual-contract-pair">${dualContractLeg(row.long_exchange,row.long_basis)}${dualContractLeg(row.short_exchange,row.short_basis)}</td><td>${dualFundingRates(row)}</td><td>${dualFundingDifference(row)}</td><td class="${signClass(row.open_spread)} numeric">${percent(row.open_spread)}</td><td class="${signClass(row.close_spread)} numeric">${percent(row.close_spread)}</td><td>${dualIndexOverlap(row)}</td></tr>`).join('')}).join('')}
function positionFloatingPopup(popup,trigger){const rect=trigger.getBoundingClientRect(),width=Math.min(540,window.innerWidth-32),left=Math.max(16,Math.min(window.innerWidth-width-16,rect.right-width));popup.style.width=`${width}px`;popup.style.left=`${left}px`;if(rect.top<360){popup.style.top=`${rect.bottom+9}px`}else{popup.style.top=`${rect.top-9}px`;popup.style.transform='translateY(-100%)'}}
function destroyFloatingPopup(){document.querySelector('[data-floating-detail]')?.remove()}
function showCommonIndexTip(trigger){destroyFloatingPopup();const row=dualIndexRows.get(trigger.closest('.common-index')?.dataset.commonIndexId);if(!row)return;const overlap=Math.max(0,Math.min(100,localIndexOverlap(row))),popup=document.createElement('div'),path=`${row.long_exchange} → ${row.short_exchange}`;popup.dataset.floatingDetail='common-index';popup.className='floating-detail-popup common-index-popup';popup.innerHTML=`<header><span><i class="index-key long"></i>${exchangeName(row.long_exchange)}</span><b class="index-path">${path}</b><span><i class="index-key short"></i>${exchangeName(row.short_exchange)}</span></header><div class="component-compare-list">${componentCompareRows(row)}</div><div class="common-index-bar"><i style="width:${overlap.toFixed(2)}%"></i></div><small>共同成分权重 ${overlap.toFixed(2)}%</small>`;document.body.appendChild(popup);positionFloatingPopup(popup,trigger)}
function showDualRefreshCountdown(seconds){clearInterval(dualMarketRefreshCountdownTimer);let remaining=Math.max(0,Number(seconds)||0),target=byId('dualFuturesCountdown');const render=()=>{target.textContent=remaining>0?` · 下次行情同步约 ${remaining} 秒`:' · 正在等待下一轮行情同步…'};render();dualMarketRefreshCountdownTimer=setInterval(()=>{remaining=Math.max(0,remaining-1);render();if(remaining===0)clearInterval(dualMarketRefreshCountdownTimer)},1000)}
function updateDualSortHeaders(){document.querySelectorAll('.dual-sort-header').forEach(button=>{const active=button.dataset.dualSort===dualSort.key;button.classList.toggle('active',active);button.textContent=button.textContent.replace(/ [↕↓↑]$/,'')+(active?(dualSort.direction==='desc'?' ↓':' ↑'):'')})}
function setDualSort(key){dualSort=dualSort.key===key?{key,direction:dualSort.direction==='desc'?'asc':'desc'}:{key,direction:'desc'};dualFuturesPage=1;updateDualSortHeaders();loadDualFutures(true)}
function changeDualFuturesPage(change){dualFuturesPage=Math.max(1,dualFuturesPage+change);loadDualFutures(true)}
function selectDualFuturesPage(page){dualFuturesPage=Math.max(1,Number(page)||1);loadDualFutures(true)}
function renderDualFuturesShell(){const target=byId('dual-futures');target.innerHTML=`<div class="strategy-hero"><p class="eyebrow">STRATEGY 01 · FUTURES / FUTURES</p><h2>期多期空套利</h2><p>固定监控 Bybit → Binance、OKX → Binance 与 Bybit → OKX 三条永续合约对冲路径。做多交易所始终在左，做空交易所始终在右；趋势与涨跌幅统一参考 Binance 合约。</p><span class="mode-pill">后台每 5 秒更新 · 页面不闪烁</span></div><div class="panel"><div class="panel-title"><div><p class="eyebrow">LIVE FUTURES / FUTURES SCANNER</p><h2>期多期空机会</h2></div><div class="spot-actions"><div class="search-suggest-wrap"><label class="search-control"><span>⌕</span><input id="dualFuturesSearch" type="search" autocomplete="off" placeholder="搜索币种，例如 BTC" oninput="setDualFuturesSearch(this.value)"></label><div id="dualFuturesSuggestions" class="symbol-suggestions hidden"></div></div><button onclick="loadDualFutures(true)">↻ 刷新数据</button></div></div><div class="table-wrap"><table><thead><tr><th>交易对 / 趋势</th><th><div class="change-header"><span>涨跌幅</span><div class="change-sort-controls"><button class="dual-sort-header" data-dual-sort="binance_change_5m" onclick="setDualSort('binance_change_5m')">5MIN</button><button class="dual-sort-header" data-dual-sort="binance_change_15m" onclick="setDualSort('binance_change_15m')">15MIN</button><button class="dual-sort-header" data-dual-sort="binance_change_30m" onclick="setDualSort('binance_change_30m')">30MIN</button><button class="dual-sort-header" data-dual-sort="binance_change_1h" onclick="setDualSort('binance_change_1h')">1H</button><button class="dual-sort-header" data-dual-sort="binance_change_12h" onclick="setDualSort('binance_change_12h')">12H</button><button class="dual-sort-header" data-dual-sort="binance_change_24h" onclick="setDualSort('binance_change_24h')">24H</button><button class="dual-sort-header" data-dual-sort="binance_change_3d" onclick="setDualSort('binance_change_3d')">3D</button><button class="dual-sort-header" data-dual-sort="binance_change_7d" onclick="setDualSort('binance_change_7d')">7D</button></div></div></th><th><button class="dual-sort-header" data-dual-sort="binance_basis" onclick="setDualSort('binance_basis')">合约路径 / 基差</button></th><th>交易所资费 / 周期</th><th><button class="dual-sort-header" data-dual-sort="funding_difference" onclick="setDualSort('funding_difference')">下期资费差</button></th><th><button class="dual-sort-header" data-dual-sort="open_spread" onclick="setDualSort('open_spread')">开差 ↓</button></th><th><button class="dual-sort-header" data-dual-sort="close_spread" onclick="setDualSort('close_spread')">平差</button></th><th>共指</th></tr></thead><tbody id="dualFuturesRows"><tr><td colspan="8" class="loading">正在连接三家交易所的公开合约行情…</td></tr></tbody></table></div><div class="pagination"><button id="dualPreviousPage" onclick="changeDualFuturesPage(-1)">← 上一页</button><label class="page-picker">跳至 <select id="dualFuturesPageSelect" onchange="selectDualFuturesPage(this.value)"></select> 页</label><span id="dualPageInfo">第 1 页</span><button id="dualNextPage" onclick="changeDualFuturesPage(1)">下一页 →</button></div><p class="data-status"><span id="dualFuturesUpdated"></span><span id="dualFuturesCountdown" class="refresh-countdown"></span></p></div>`}
async function loadDualFutures(manual=false){if(dualFuturesLoading||!byId('dualFuturesRows'))return;dualFuturesLoading=true;const status=byId('dualFuturesUpdated');if(manual)status.textContent='正在读取后台已缓存的合约行情…';try{const response=await fetch('/api/dual-futures?page='+dualFuturesPage+'&symbol='+encodeURIComponent(dualFuturesSearch)+'&sort_by='+dualSort.key+'&sort_direction='+dualSort.direction);const data=await response.json();if(!response.ok)throw new Error(data.error||'期多期空行情暂时无法读取');destroyFloatingPopup();dualBasisOpenings=Object.fromEntries(data.symbols.map(group=>[group.symbol,group.basis_opening]));dualIndexRows=new Map();data.symbols.forEach(group=>group.rows.forEach(row=>{row._commonIndexId=`${group.symbol}|${row.long_exchange}|${row.short_exchange}`;dualIndexRows.set(row._commonIndexId,row)}));byId('dualFuturesRows').innerHTML=data.symbols.length?dualRows(data.symbols):'<tr><td colspan="10" class="loading">没有符合条件的合约路径。</td></tr>';dualFuturesHasData=true;updateDualSortHeaders();byId('dualPageInfo').textContent=`第 ${data.page} / ${data.pages} 页 · 共 ${data.total_symbols} 个币种`;const pageSelect=byId('dualFuturesPageSelect');pageSelect.innerHTML=Array.from({length:data.pages},(_,index)=>`<option value="${index+1}" ${index+1===data.page?'selected':''}>${index+1}</option>`).join('');byId('dualPreviousPage').disabled=data.page<=1;byId('dualNextPage').disabled=data.page>=data.pages;status.textContent=`最近更新 ${data.updated_at} · 已对全部 ${data.total_symbols} 个币种排序 · 当前按 ${dualSort.key} 排序`;showDualRefreshCountdown(data.next_refresh_in_seconds)}catch(error){if(!dualFuturesHasData)byId('dualFuturesRows').innerHTML=`<tr><td colspan="10" class="loading">${error.message}</td></tr>`;status.textContent=dualFuturesHasData?'本次更新失败，已保留上一组有效数据。':error.message}finally{dualFuturesLoading=false}}
function addDualLiquidityHeader(){const table=byId('dual-futures')?.querySelector('table');if(!table)return;const header=table.querySelector('thead tr');const changeHeader=header?.querySelector('.change-header')?.closest('th');if(changeHeader&&!header.querySelector('.liquidity-column')){const column=document.createElement('th');column.className='liquidity-column';column.textContent='流动性';changeHeader.insertAdjacentElement('afterend',column)}table.querySelectorAll('td[colspan="8"]').forEach(cell=>cell.colSpan=9)}
function addDualBasisSortControls(){const button=byId('dual-futures')?.querySelector('[data-dual-sort="binance_basis"]');if(!button||button.closest('.basis-sort-controls'))return;const wrapper=document.createElement('div');wrapper.className='basis-sort-controls';wrapper.innerHTML='<span>合约基差</span><div><button class="dual-sort-header" data-dual-sort="binance_basis" onclick="setDualSort(\'binance_basis\')">BN</button><button class="dual-sort-header" data-dual-sort="bybit_basis" onclick="setDualSort(\'bybit_basis\')">BY</button><button class="dual-sort-header" data-dual-sort="okx_basis" onclick="setDualSort(\'okx_basis\')">OK</button></div>';button.replaceWith(wrapper)}
function alertLabel(type){return type==='futures_pump'?'合约拉升':type==='spot_pump'?'现货拉升':type==='rapid_spread'?'开差速变':type==='rapid_basis'?'基差速变':type==='dual_spread_threshold'?'开差异动':type==='dual_basis_threshold'?'BN 基差异动':'基差异动'}
function alertClass(type){return type==='futures_pump'?'futures':type==='spot_pump'?'spot':type==='rapid_spread'?'rapid-spread':type==='rapid_basis'?'rapid-basis':'basis'}
function alertMetric(value){return value===null||value===undefined?'—':percent(value)}
function strategyLabel(strategy){return strategy==='futures_futures'?'期多期空':'现多期空'}
function alertExchangeLeg(exchange,market,interval){return `<span>${exchangeName(exchange)} ${market}${interval?` <em class="interval-badge ${intervalClass(interval)}">${interval}H</em>`:''}</span>`}
function alertExchangePair(item){return `<div class="alert-exchange-pair">${alertExchangeLeg(item.long_exchange,item.long_market,item.long_interval)}<b>→</b>${alertExchangeLeg(item.short_exchange,item.short_market,item.short_interval)}</div>`}
function toggleTips(){byId('tipsPanel').classList.toggle('collapsed')}
function updateAlarmSoundButton(){const button=byId('alarmSoundToggle');if(button){button.textContent=alarmSoundEnabled?'报警声音：开启':'报警声音：静音';button.classList.toggle('enabled',alarmSoundEnabled)}}
async function playAlarmSound(force=false){if(!force&&!alarmSoundEnabled)return;try{alarmAudioContext=alarmAudioContext||new (window.AudioContext||window.webkitAudioContext)();if(alarmAudioContext.state==='suspended')await alarmAudioContext.resume();Array.from({length:12},(_,index)=>index*.125).forEach((offset,index)=>{const oscillator=alarmAudioContext.createOscillator(),gain=alarmAudioContext.createGain();oscillator.type='square';oscillator.frequency.value=index%2?880:1175;gain.gain.setValueAtTime(.0001,alarmAudioContext.currentTime+offset);gain.gain.exponentialRampToValueAtTime(.55,alarmAudioContext.currentTime+offset+.01);gain.gain.exponentialRampToValueAtTime(.0001,alarmAudioContext.currentTime+offset+.105);oscillator.connect(gain).connect(alarmAudioContext.destination);oscillator.start(alarmAudioContext.currentTime+offset);oscillator.stop(alarmAudioContext.currentTime+offset+.11)})}catch(error){}}
function toggleAlarmSound(){alarmSoundEnabled=!alarmSoundEnabled;localStorage.setItem('arbi-alarm-sound',alarmSoundEnabled?'on':'off');updateAlarmSoundButton();if(alarmSoundEnabled)playAlarmSound()}
function testAlarmSound(){playAlarmSound(true)}
function alertDeathMarkup(item){const expiresAt=Date.now()+Math.max(0,Number(item.remaining_seconds)||0)*1000;return `<small class="alert-death" data-alert-expires="${expiresAt}">${item.created_at} · 剩余 ${item.remaining_seconds}s</small>`}
function updateAlertCountdowns(){let expired=false;document.querySelectorAll('.alert-death').forEach(node=>{const remaining=Math.max(0,Math.ceil((Number(node.dataset.alertExpires)-Date.now())/1000));node.textContent=node.textContent.replace(/剩余 \d+s$/,`剩余 ${remaining}s`);if(remaining===0)expired=true});if(expired)loadAlerts(true)}
function startAlertCountdown(){clearInterval(alertCountdownTimer);updateAlertCountdowns();alertCountdownTimer=setInterval(updateAlertCountdowns,1000)}
function alertTimelineNode(item){return `<li class="alert-timeline-node ${alertClass(item.type)}"><i></i><div><time>${item.created_at}</time><b>${strategyLabel(item.strategy)} · ${alertLabel(item.type)}</b>${alertExchangePair(item)}<span>开差 <em class="${changeClass(item.open_spread)}">${alertMetric(item.open_spread)}</em> · 基差 <em class="${changeClass(item.basis)}">${alertMetric(item.basis)}</em></span></div></li>`}
function alertDetailCard(group){const latest=group.latest;return `<article class="alert-detail-card ${alertClass(latest.type)}"><header><div><div class="alert-card-title"><h4>${group.symbol}</h4><span class="strategy-badge">${group.alert_count} 次报警</span></div><span class="alert-latest-label">最近：${strategyLabel(latest.strategy)} · ${alertLabel(latest.type)} · ${latest.created_at}</span></div><div class="alert-values"><span>开差 <b class="${changeClass(latest.open_spread)}">${alertMetric(latest.open_spread)}</b></span><span>基差 <b class="${changeClass(latest.basis)}">${alertMetric(latest.basis)}</b></span></div></header>${alertExchangePair(latest)}<ol class="alert-timeline">${group.timeline.map(alertTimelineNode).join('')}</ol></article>`}
function renderAlertMasterDetail(groups){latestAlertGroups=groups;if(!groups.some(group=>group.symbol===selectedAlertSymbol))selectedAlertSymbol=groups[0]?.symbol||'';const selected=groups.find(group=>group.symbol===selectedAlertSymbol);byId('alertEvents').innerHTML=groups.length?`<div class="alert-symbol-list">${groups.map(group=>{const latest=group.latest;return `<button class="alert-symbol-option ${group.symbol===selectedAlertSymbol?'active':''} ${alertClass(latest.type)}" onclick="selectAlertSymbol('${group.symbol}')"><b>${group.symbol}</b><span>${latest.created_at} · ${alertLabel(latest.type)}</span><small>${group.alert_count} 次 · 开差 ${alertMetric(latest.open_spread)} · 基差 ${alertMetric(latest.basis)}</small></button>`}).join('')}</div><div class="alert-detail-pane">${alertDetailCard(selected)}</div>`:'<p class="empty-alert">暂时没有确认后的报警。</p>'}
function selectAlertSymbol(symbol){selectedAlertSymbol=symbol;renderAlertMasterDetail(latestAlertGroups)}
async function loadAlerts(force=false){try{const data=await (await fetch('/api/alerts')).json(),activeEvents=data.active_events||[];const signature=activeEvents.map(item=>`${item.symbol}-${item.type}-${item.open_spread}-${item.basis}-${item.created_at}`).join('|');const hasNewAlert=alertsInitialized&&signature!==alertSignature&&activeEvents.length>0;if(!force&&signature===alertSignature)return;alertSignature=signature;renderAlertMasterDetail(data.events||[]);byId('basisTracking').innerHTML=data.basis_tracking.length?data.basis_tracking.map(item=>`<article class="alert-item basis"><div class="alert-card-title"><h4>${item.symbol}</h4><span class="strategy-badge">${strategyLabel(item.strategy)} · 基差追踪</span></div><p class="tracking-max">最大 ${percent(item.max_basis)}</p><div class="meta"><span>已记录至 ${item.last_level.toFixed(1)}%</span><span>最大时间 ${item.max_at}</span></div></article>`).join(''):'<p class="empty-alert">暂无正在追踪的基差扩展。</p>';byId('tipsCount').textContent=activeEvents.length;byId('tipsItems').innerHTML=activeEvents.length?activeEvents.map(item=>`<article class="tips-item ${alertClass(item.type)}"><b>${item.symbol} · ${strategyLabel(item.strategy)} · ${alertLabel(item.type)}</b>${alertExchangePair(item)}<span>开差 ${alertMetric(item.open_spread)} · 基差 ${alertMetric(item.basis)}</span>${alertDeathMarkup(item)}</article>`).join(''):'<p class="empty-alert">当前没有处于 120 秒有效期的报警。</p>';startAlertCountdown();alertsInitialized=true;if(hasNewAlert)playAlarmSound()}catch(error){byId('alertEvents').innerHTML='<p class="empty-alert">报警记录暂时无法读取。</p>';byId('tipsItems').innerHTML='<p class="empty-alert">报警暂时无法读取。</p>'}}
document.querySelectorAll('nav a[data-view]').forEach(link=>link.addEventListener('click',event=>{event.preventDefault();const viewId=link.dataset.view;document.querySelectorAll('.view').forEach(view=>view.classList.toggle('active',view.id===viewId));document.querySelectorAll('nav a[data-view]').forEach(item=>item.classList.toggle('active',item===link));if(viewId==='alerts')loadAlerts(true);if(viewId==='daily-trends')loadDailyTrends();if(viewId==='daily-listings')loadDailyListings();window.location.hash=viewId}));
function basisOpeningMarkup(opening,key){if(!opening)return '<span class="basis-opening-empty">—</span>';basisOpeningDetails.set(key,opening);return `<div class="basis-opening"><b data-basis-opening-id="${key}" onmouseenter="showBasisOpeningTip(this)" onmouseleave="destroyFloatingPopup()">打开 × ${opening.open_count||1}</b><span>${percent(opening.opened_basis)}</span><small>最近 ${opening.opened_at}</small></div>`}
function showBasisOpeningTip(trigger){destroyFloatingPopup();const opening=basisOpeningDetails.get(trigger.dataset.basisOpeningId);if(!opening)return;const popup=document.createElement('div');popup.dataset.floatingDetail='basis-opening';popup.className='floating-detail-popup basis-opening-popup';popup.innerHTML=`<strong>基差最近打开</strong><dl><div><dt>首次越阈</dt><dd>${percent(opening.opened_basis)} · ${opening.opened_at}</dd></div><div><dt>近期最大</dt><dd>${percent(opening.max_basis)} · ${opening.max_at}</dd></div><div><dt>打开次数</dt><dd>${opening.open_count||1} 次</dd></div></dl><small>首次绝对值越过 1%，每扩大 0.2% 计一次</small>`;document.body.appendChild(popup);positionFloatingPopup(popup,trigger)}
function addBasisOpeningCells(targetId,prefix,openings){const target=byId(targetId);if(!target)return;target.querySelectorAll(`tr.${prefix}-group-start`).forEach(row=>{if(row.querySelector('.basis-opening-cell'))return;const symbol=row.querySelector('td.symbol>div:last-of-type>span')?.textContent;if(!symbol)return;const span=Number(row.querySelector('td.symbol')?.rowSpan)||1;const key=`${prefix}:${symbol}`;row.insertAdjacentHTML('beforeend',`<td class="basis-opening-cell" rowspan="${span}">${basisOpeningMarkup(openings[symbol],key)}</td>`)})}
function addBasisOpeningHeaders(){const spotHeader=byId('spot-futures')?.querySelector('table thead tr');if(spotHeader&&!spotHeader.querySelector('.basis-opening-column'))spotHeader.insertAdjacentHTML('beforeend','<th class="basis-opening-column">基差打开</th>');const dualHeader=byId('dual-futures')?.querySelector('table thead tr');if(dualHeader&&!dualHeader.querySelector('.basis-opening-column'))dualHeader.insertAdjacentHTML('beforeend','<th class="basis-opening-column">基差打开</th>')}
function applyGroupFrameClasses(targetId,prefix){const target=byId(targetId);if(!target)return;let rowsRemaining=0;[...target.querySelectorAll('tr')].forEach(row=>{row.classList.remove(`${prefix}-group-start`,`${prefix}-group-body`,`${prefix}-group-end`);const symbolCell=row.querySelector('td.symbol[rowspan]');if(symbolCell){rowsRemaining=Number(symbolCell.rowSpan)||1;row.classList.add(`${prefix}-group-start`);if(rowsRemaining===1)row.classList.add(`${prefix}-group-end`)}else if(rowsRemaining===1){row.classList.add(`${prefix}-group-end`)}else if(rowsRemaining>1){row.classList.add(`${prefix}-group-body`)}rowsRemaining=Math.max(0,rowsRemaining-1)});addBasisOpeningCells(targetId,prefix,prefix==='spot'?spotBasisOpenings:dualBasisOpenings);const dividerClass=`${prefix}-group-divider`,columns=prefix==='spot'?12:10;if(!target.querySelector(`.${dividerClass}`))target.querySelectorAll(`tr.${prefix}-group-end`).forEach(row=>row.insertAdjacentHTML('afterend',`<tr class="${dividerClass}" aria-hidden="true"><td colspan="${columns}"></td></tr>`))}
function installGroupFrameObservers(){[['dualFuturesRows','dual'],['spotFuturesRows','spot']].forEach(([targetId,prefix])=>{const target=byId(targetId);if(!target)return;new MutationObserver(()=>applyGroupFrameClasses(targetId,prefix)).observe(target,{childList:true});applyGroupFrameClasses(targetId,prefix)})}
async function loadDailyListings(){const data=await (await fetch('/api/daily-report/listings')).json(),groups={};data.events.forEach(item=>(groups[item.exchange]??=[]).push(item));byId('dailyListings').innerHTML=Object.keys(groups).length?Object.entries(groups).map(([exchange,items])=>`<section class="listing-exchange"><h3>${exchange}</h3>${items.map(item=>`<article><b>${item.symbol}</b><span class="listing-${item.type==='上架'?'up':'down'}">${item.type}</span><small>公告收录：${item.occurred_at}${item.effective_at?` · 执行时间：${item.effective_at}`:' · 执行时间待解析'}${item.title?` · ${item.title}`:''}</small></article>`).join('')}</section>`).join(''):'<p class="empty-alert">暂无已入库的交易所公告。</p>'}
async function loadSimpleThinking(){const section=byId('thinking');if(!section)return;let target=byId('simpleThinkingList');if(!target){section.insertAdjacentHTML('beforeend','<div class="panel simple-thinking"><div id="simpleThinkingList" class="thinking-columns"></div></div>');target=byId('simpleThinkingList')}const thinkingInterval=interval=>interval?`<em class="interval-badge ${intervalClass(interval)}">${interval}H</em>`:'',thinkingLeg=(side,exchange,openInterest,volume,isSpot,interval)=>`<div class="thinking-leg ${side==='做多'?'long':'short'}"><b>${side}</b><span class="thinking-exchange">${exchangeName(exchange)}${thinkingInterval(interval)}</span><div class="thinking-metrics">${isSpot?liquidityMetric('交易量',volume):`${liquidityMetric('持仓量',openInterest)}${liquidityMetric('交易量',volume)}`}</div></div>`,thinkingFunding=item=>`<div class="thinking-funding"><span>当前 <b class="${changeClass(item.funding_current)}">${percent(item.funding_current)}</b></span><span>上期 <b class="${changeClass(item.funding_previous)}">${percent(item.funding_previous)}</b></span><span>24H <b class="${changeClass(item.funding_24h)}">${percent(item.funding_24h)}</b></span><span>3D <b class="${changeClass(item.funding_3d)}">${percent(item.funding_3d)}</b></span></div>`,data=await (await fetch('/api/arbitrage-thinking/simple')).json(),render=items=>items.map(item=>`<article><b><button class="symbol-detail-trigger" onclick="openSymbolDetail('${item.symbol}')">${item.symbol}</button></b><span class="positive">开差 ${percent(item.open_spread)} · 平差 ${percent(item.close_spread)}</span>${thinkingFunding(item)}<div class="thinking-liquidity">${thinkingLeg('做多',item.long_exchange,item.long_open_interest,item.long_volume,item.long_is_spot,item.long_interval)}${thinkingLeg('做空',item.short_exchange,item.short_open_interest,item.short_volume,item.short_is_spot,item.short_interval)}</div></article>`).join('')||'<p class="empty-alert">当前没有符合条件的币种。</p>';target.innerHTML=`<section><h3>现多期空</h3>${render(data.spot_simple)}</section><section><h3>期多期空</h3>${render(data.dual_simple)}</section>`}
const openSymbolDetailBase=openSymbolDetail;window.openSymbolDetail=async function(symbol){await openSymbolDetailBase(symbol);const modal=byId('symbolDetailModal');if(!modal)return;const start=byId('detailFundingStart')?.value||'',end=byId('detailFundingEnd')?.value||'',data=await (await fetch(`/api/symbol-detail?symbol=${encodeURIComponent(symbol)}&start=${start}&end=${end}`)).json(),heading=[...modal.querySelectorAll('h3')].find(node=>node.textContent.includes('现货'));if(heading&&!modal.querySelector('.trend-detail'))heading.insertAdjacentHTML('beforebegin',`<h3>价格走势</h3><div class="trend-detail">${trendPeriods.map(([key,label])=>`<span><b>${label}</b><em class="${changeClass(data.trends[key])}">${displayChange(data.trends[key])}</em></span>`).join('')}</div>`)};
let gainersPeriod='change_24h';
function detailMoney(value){const n=Number(value);if(!Number.isFinite(n))return '—';if(Math.abs(n)>=1e9)return `$${(n/1e9).toFixed(2)}B`;if(Math.abs(n)>=1e6)return `$${(n/1e6).toFixed(2)}M`;return money(n)}
function detailRows(rows,fields){return rows.map(row=>`<article>${fields.map(([label,key])=>`<span><b>${label}</b>${key==='exchange'?exchangeName(row[key]):key==='basis'?`${Number(row[key]).toFixed(3)}%`:detailMoney(row[key])}</span>`).join('')}</article>`).join('')||'<p>暂无数据</p>'}
async function openSymbolDetail(symbol){let modal=byId('symbolDetailModal');const priorStart=byId('detailFundingStart')?.value,priorEnd=byId('detailFundingEnd')?.value;if(!modal){document.body.insertAdjacentHTML('beforeend','<section id="symbolDetailModal" class="modal hidden"></section>');modal=byId('symbolDetailModal')}modal.classList.remove('hidden');modal.innerHTML='<div class="dialog symbol-detail-dialog"><button class="close" onclick="closeSymbolDetail()">×</button><p>正在读取详情…</p></div>';const start=priorStart||new Date(Date.now()-7*86400000).toISOString().slice(0,10),end=priorEnd||new Date().toISOString().slice(0,10),data=await (await fetch(`/api/symbol-detail?symbol=${encodeURIComponent(symbol)}&start=${start}&end=${end}`)).json(),daily=Object.entries(data.funding_daily||{});modal.innerHTML=`<div class="dialog symbol-detail-dialog"><button class="close" onclick="closeSymbolDetail()">×</button><h2>${data.symbol} 详情</h2><h3>现货价格</h3><div class="detail-grid">${detailRows(data.spot,[['交易所','exchange'],['价格','mid'],['24H量','volume_24h']])}</div><h3>合约价格</h3><div class="detail-grid">${detailRows(data.futures,[['交易所','exchange'],['价格','mid'],['基差','basis'],['持仓','open_interest'],['24H量','volume_24h']])}</div><h3>共指信息</h3><div class="index-detail">${data.binance_index_components.length?data.binance_index_components.map(item=>`${item.name||item.component||'成分'} ${item.weight||item.proportion||''}`).join(' · '):'Binance 指数成分待同步'}</div><h3>Binance 资金费</h3><div class="detail-dates"><input id="detailFundingStart" type="date" value="${start}"><input id="detailFundingEnd" type="date" value="${end}"><button onclick="openSymbolDetail('${data.symbol}')">查询</button></div><div class="funding-columns"><div><b>每日总资费</b>${daily.map(([day,rate])=>`<span>${day}<em class="${changeClass(rate)}">${percent(rate)}</em></span>`).join('')||'暂无数据'}</div><div><b>每一期资金费</b>${data.funding.map(item=>`<span>${item.time}<em class="${changeClass(item.rate)}">${percent(item.rate)}</em></span>`).join('')||'暂无数据'}</div></div><p class="funding-total">区间总资费：<b class="${changeClass(data.funding_total)}">${percent(data.funding_total)}</b></p></div>`}
function closeSymbolDetail(){byId('symbolDetailModal')?.classList.add('hidden')}
const gainersPeriods=[['change_5m','5MIN'],['change_15m','15MIN'],['change_30m','30MIN'],['change_1h','1H'],['change_4h','4H'],['change_12h','12H'],['change_24h','24H']];
function renderGainersShell(){if(byId('gainers-losers'))return;const dailyNav=document.querySelector('.daily-nav');dailyNav?.insertAdjacentHTML('afterend','<a data-view="gainers-losers" href="#gainers-losers" onclick="showGainersView(event)">涨跌幅榜</a>');const header='<div class="gainer-table-head"><span>#</span><span>币种</span><span>价格</span><span>价格变化</span><span>24小时成交额</span></div>';document.querySelector('main')?.insertAdjacentHTML('beforeend',`<section id="gainers-losers" class="view"><div class="panel-title"><div><p class="eyebrow">BINANCE MARKET MOVERS</p><h2>涨跌幅榜</h2><p class="sub">基于 Binance 合约中间价与本地 5 分钟快照计算。</p></div></div><div id="gainersPeriodControls" class="gainers-periods"></div><div class="daily-grid"><article class="panel"><p class="eyebrow">TOP RISING</p>${header}<div id="gainersRising" class="daily-list gainer-table"></div></article><article class="panel"><p class="eyebrow">TOP FALLING</p>${header}<div id="gainersFalling" class="daily-list gainer-table"></div></article></div></section>`);byId('gainersPeriodControls').innerHTML=gainersPeriods.map(([key,label])=>`<button class="${key===gainersPeriod?'active':''}" onclick="setGainersPeriod('${key}')">${label}</button>`).join('')}
function gainersItem(item,index){return `<article class="gainer-row"><i>${index+1}</i><b>${item.symbol}</b><span>${money(item.price)}</span><span class="${changeClass(item.change)}">${displayChange(item.change)}</span><span>${liquidityAmount(item.volume_24h)}</span></article>`}
async function loadGainers(){const data=await (await fetch('/api/gainers-losers?period='+gainersPeriod)).json();byId('gainersRising').innerHTML=data.rising.length?data.rising.map(gainersItem).join(''):'<p class="empty-alert">正在积累该周期数据。</p>';byId('gainersFalling').innerHTML=data.falling.length?data.falling.map(gainersItem).join(''):'<p class="empty-alert">正在积累该周期数据。</p>'}
function setGainersPeriod(period){gainersPeriod=period;byId('gainersPeriodControls').innerHTML=gainersPeriods.map(([key,label])=>`<button class="${key===gainersPeriod?'active':''}" onclick="setGainersPeriod('${key}')">${label}</button>`).join('');loadGainers()}
function showGainersView(event){event?.preventDefault();document.querySelectorAll('.view').forEach(view=>view.classList.toggle('active',view.id==='gainers-losers'));document.querySelectorAll('nav a[data-view]').forEach(item=>item.classList.toggle('active',item.dataset.view==='gainers-losers'));loadGainers();window.location.hash='gainers-losers'}
function thoughtPrice(value){const n=Number(value);return Number.isFinite(n)?n.toFixed(8):'暂无'}
function thoughtPercent(value){return value===null||value===undefined?'暂无':percent(value)}
function thoughtLarge(value){const n=Number(value);if(!Number.isFinite(n))return '暂无';if(Math.abs(n)>=1e9)return `$${(n/1e9).toFixed(2)}B`;if(Math.abs(n)>=1e6)return `$${(n/1e6).toFixed(2)}M`;return `$${n.toFixed(2)}`}
function thoughtList(items){return `<ul>${items.map(item=>`<li>${item}</li>`).join('')}</ul>`}
function thoughtValidation(item){const validation=item.validation||{};return ['30m','1h','2h'].map(key=>{const row=validation[key]||{};return `<span>${key.toUpperCase()} <b class="${changeClass(row.price_change)}">价 ${thoughtPercent(row.price_change)}</b><i>持仓 ${thoughtPercent(row.oi_change)} · 人数比 ${thoughtPercent(row.ratio_change)} · CVD ${thoughtLarge(row.cvd)} · 量 ${thoughtLarge(row.volume)}</i></span>`}).join('')}
function toggleThoughtShot(id){byId(id)?.classList.toggle('hidden')}
const expandedThoughts=new Set();
function toggleThoughtRecord(id,button){const detail=byId(`thought-detail-${id}`);if(!detail)return;detail.classList.toggle('hidden');const opened=!detail.classList.contains('hidden');opened?expandedThoughts.add(id):expandedThoughts.delete(id);const label=button?.querySelector('em');if(label)label.textContent=opened?'收起':'展开'}
function thoughtProfitLabel(item){if(item.trade_status==='已平仓')return `<span class="${changeClass(item.realized_profit_pct)}">已实现 ${thoughtPercent(item.realized_profit_pct)}</span>`;if(item.profit_pct!==null&&item.profit_pct!==undefined)return `<span class="${changeClass(item.profit_pct)}">浮盈 ${thoughtPercent(item.profit_pct)}</span>`;return `<span>胜率 ${item.thesis_win_rate?.rate??0}%</span>`}
function thoughtSideClass(item){return item.trade_side==='做多'?'long':(item.trade_side==='做空'?'short':'watch')}
function thoughtSideBadge(item){return `<span class="thought-side-badge ${thoughtSideClass(item)}">${item.trade_side||'观察'}</span>`}
function thoughtSummaryLine(item){const side=item.trade_side||'观察',status=item.trade_status||'盯盘',entry=item.entry!==null&&item.entry!==undefined?` · 入场 ${thoughtPrice(item.entry)}`:'';if(item.trade_status==='已平仓')return `${side} · ${status}${entry} · 止盈 ${thoughtPrice(item.exit)} · 当前 ${thoughtPrice(item.last)}`;return `${side} · ${status}${entry} · 当前 ${thoughtPrice(item.last)}`}
function thoughtCard(item){const id=item.symbol.replace(/[^A-Z0-9]/g,''),shotId=`thought-shot-${id}`,expanded=expandedThoughts.has(id);return `<article class="thought-card compact ${thoughtSideClass(item)}"><button type="button" class="thought-summary" onclick="toggleThoughtRecord('${id}',this)"><span><b>${item.symbol} ${thoughtSideBadge(item)}</b><i>${thoughtSummaryLine(item)}</i></span>${thoughtProfitLabel(item)}<strong>胜率 ${item.thesis_win_rate?.rate??0}%</strong><em>${expanded?'收起':'展开'}</em></button><div id="thought-detail-${id}" class="thought-detail ${expanded?'':'hidden'}"><div class="thought-card-head"><div><p class="eyebrow">ACTIVE REVIEW</p><h3>${item.symbol} 犄型走势复盘 ${thoughtSideBadge(item)}</h3><small>${item.trade_side||'观察'} · ${item.trade_status||'盯盘'} · 入场 ${thoughtPrice(item.entry)} · 入场时间 ${item.entry_time||'待记录'} · 当前价格 ${thoughtPrice(item.last)} · 思路胜率 ${item.thesis_win_rate?.rate??0}%</small></div><div class="thought-actions"><button type="button" class="shot-toggle" onclick="event.stopPropagation();toggleThoughtShot('${shotId}')">截图</button><a class="kline-link" target="_blank" rel="noopener noreferrer" href="${coinglassKlineUrl(item.symbol)}" onclick="event.stopPropagation()">K线</a></div></div>${item.screenshot_url?`<div id="${shotId}" class="thought-shot hidden"><img src="${item.screenshot_url}" alt="${item.symbol} CoinGlass 数据截图"></div>`:''}<section class="user-thesis"><h4>你的思路（主线）</h4><p>${item.my_thesis}</p></section><section class="assistant-thesis"><h4>我的验证与风险提醒</h4><p>${item.assistant_thesis}</p></section>${item.challenge_points?.length?`<section class="challenge-points"><h4>我不完全认可 / 需要提醒你的地方</h4>${thoughtList(item.challenge_points)}</section>`:''}<section><h4>盯盘验证</h4><p>${item.validation_view}</p><div class="thought-validation">${thoughtValidation(item)}</div></section><div class="thought-two-col"><section><h4>止盈计划</h4>${thoughtList(item.take_profit)}</section><section><h4>止损计划</h4>${thoughtList(item.stop_loss)}</section></div><section><h4>复盘与修正</h4>${thoughtList(item.review_notes)}</section><p class="thought-source">${item.thesis_win_rate?.note||''} · 数据来源：${item.source==='live'?'Binance 公开实时接口':'本地快照降级'} · 默认只展示简洁记录，点开后查看完整分析。</p></div></article>`}
async function loadThoughtAnalysis(){const target=byId('thoughtAnalysis');if(!target)return;if(!target.dataset.loaded&&!target.children.length)target.innerHTML='<p class="loading">正在读取思路分析…</p>';target.classList.add('soft-loading');try{const data=await (await fetch('/api/daily-report/thoughts')).json();target.dataset.loaded='1';target.innerHTML=data.items?.length?data.items.map(thoughtCard).join(''):'<p class="empty-alert">暂无思路分析记录。</p>'}catch(error){if(!target.dataset.loaded)target.innerHTML='<p class="empty-alert">思路分析暂时无法读取。</p>'}finally{target.classList.remove('soft-loading')}}
document.querySelectorAll('nav a[data-view="daily-thoughts"]').forEach(link=>link.addEventListener('click',()=>loadThoughtAnalysis()));
renderGainersShell();renderDualFuturesShell();addDualLiquidityHeader();addDualBasisSortControls();addBasisOpeningHeaders();installGroupFrameObservers();updateAlarmSoundButton();updateSortHeaders();updateDualSortHeaders();loadDashboard();loadStrategies();loadSpotFutures();loadDualFutures();loadAlerts(true);loadSimpleThinking();loadThoughtAnalysis();setInterval(loadDashboard,5000);setInterval(loadSpotFutures,5000);setInterval(loadDualFutures,5000);setInterval(loadAlerts,5000);setInterval(loadSimpleThinking,30000);setInterval(loadThoughtAnalysis,300000);
document.addEventListener('click',event=>{if(event.target.id==='symbolDetailModal')closeSymbolDetail()});
